import type { ReactiveController, ReactiveControllerHost } from 'lit';

/**
 * 插槽检测控制器。
 *
 * 实现 Lit 的 ReactiveController 接口，用于判断宿主元素的 Shadow DOM 中
 * 是否存在 default slot 或具名 slot 的内容。
 *
 * 工作流程：
 *   1. hostConnected 时在 shadowRoot 上注册 slotchange 事件监听
 *   2. 当 slot 内容变化时，handleSlotChange 检查变化的 slot 是否在关注列表中
 *   3. 如果匹配，触发宿主元素的 requestUpdate() 重新渲染
 *   4. hostDisconnected 时移除事件监听
 *
 * 提供 test(slotName) 方法用于在渲染模板中同步判断 slot 是否有内容，
 * 特殊值 '[default]' 表示检测默认插槽。
 */
export class HasSlotController implements ReactiveController {
  host: ReactiveControllerHost & Element;
  /** 关注的 slot 名称列表，'[default]' 表示默认插槽 */
  slotNames: string[] = [];

  /**
   * @param host - 宿主元素（实现了 ReactiveControllerHost 的 DOM 元素）
   * @param slotNames - 需要监听的 slot 名称列表
   */
  constructor(host: ReactiveControllerHost & Element, ...slotNames: string[]) {
    (this.host = host).addController(this);
    this.slotNames = slotNames;
  }

  /**
   * 检测默认插槽（无 name 属性的 slot）中是否存在可渲染内容。
   *
   * 遍历宿主元素的直接子节点（childNodes）：
   *   - 文本节点：去除空白后非空 → 有内容
   *   - 元素节点：排除 <sl-visually-hidden>（视觉隐藏元素），
   *     无 slot 属性的元素视为默认插槽内容
   *
   * @returns 默认插槽中有内容返回 true
   */
  private hasDefaultSlot() {
    return [...this.host.childNodes].some(node => {
      if (node.nodeType === node.TEXT_NODE && node.textContent!.trim() !== '') {
        return true;
      }

      if (node.nodeType === node.ELEMENT_NODE) {
        const el = node as HTMLElement;
        const tagName = el.tagName.toLowerCase();

        // Ignore visually hidden elements since they aren't rendered
        if (tagName === 'sl-visually-hidden') {
          return false;
        }

        // If it doesn't have a slot attribute, it's part of the default slot
        if (!el.hasAttribute('slot')) {
          return true;
        }
      }

      return false;
    });
  }

  /**
   * 检测指定名称的具名插槽中是否存在内容。
   *
   * 使用 :scope > [slot="name"] 选择器仅在宿主元素的直接子节点范围内查找。
   *
   * @param name - 插槽名称（slot 属性的值）
   * @returns 存在匹配的元素返回 true
   */
  private hasNamedSlot(name: string) {
    return this.host.querySelector(`:scope > [slot="${name}"]`) !== null;
  }

  /**
   * 同步检测指定 slot 是否有内容。
   *
   * @param slotName - '[default]' 检测默认插槽，否则检测对应的具名插槽
   * @returns 插槽存在内容返回 true
   */
  test(slotName: string) {
    return slotName === '[default]' ? this.hasDefaultSlot() : this.hasNamedSlot(slotName);
  }

  /**
   * Lit 生命周期：宿主元素连接到 DOM 时调用。
   *
   * 在 shadowRoot 上注册 slotchange 事件监听，
   * 用于响应 slot 内容的动态变化（如条件渲染、列表更新）。
   */
  hostConnected() {
    this.host.shadowRoot!.addEventListener('slotchange', this.handleSlotChange);
  }

  /**
   * Lit 生命周期：宿主元素从 DOM 断开时调用。
   *
   * 移除 slotchange 事件监听，防止内存泄漏。
   */
  hostDisconnected() {
    this.host.shadowRoot!.removeEventListener('slotchange', this.handleSlotChange);
  }

  /**
   * slotchange 事件处理器（箭头函数绑定 this）。
   *
   * 当 slot 的分配节点发生变化时触发：
   *   - 有 name 的 slot → 与 slotNames 列表中的名称匹配
   *   - 无 name 的 slot → 匹配 '[default]'
   *
   * 匹配成功后调用 host.requestUpdate() 触发 Lit 的异步重渲染。
   */
  private handleSlotChange = (event: Event) => {
    const slot = event.target as HTMLSlotElement;

    if ((this.slotNames.includes('[default]') && !slot.name) || (slot.name && this.slotNames.includes(slot.name))) {
      this.host.requestUpdate();
    }
  };
}

/**
 * 获取 slot 中所有已分配节点的 HTML 字符串。
 *
 * 通过 slot.assignedNodes({ flatten: true }) 获取扁平化后的所有分配节点
 * （包括嵌套 slot 的最终内容），然后拼接：
 *   - 元素节点 → outerHTML（完整的标签+内容+属性）
 *   - 文本节点 → textContent
 *
 * 为什么不用 slot.innerHTML：
 *   slot.innerHTML 返回的是 slot 标签内部的 fallback 内容，而非
 *   实际分配到该 slot 的外部内容。Web 标准中从宿主 light DOM 分配到
 *   Shadow DOM 的内容不会出现在 innerHTML 中，因此必须通过
 *   assignedNodes 手动遍历拼接。
 *
 * @param slot - HTMLSlotElement 实例
 * @returns 分配内容的 HTML 字符串
 */
export function getInnerHTML(slot: HTMLSlotElement): string {
  const nodes = slot.assignedNodes({ flatten: true });
  let html = '';

  [...nodes].forEach(node => {
    if (node.nodeType === Node.ELEMENT_NODE) {
      html += (node as HTMLElement).outerHTML;
    }

    if (node.nodeType === Node.TEXT_NODE) {
      html += node.textContent;
    }
  });

  return html;
}

/**
 * 获取 slot 中所有已分配文本节点的纯文本内容。
 *
 * 与 getInnerHTML 不同，此函数仅提取文本节点，忽略所有元素节点。
 * 通过 slot.assignedNodes({ flatten: true }) 获取分配节点列表，
 * 过滤出 TEXT_NODE 类型并拼接其 textContent。
 *
 * 为什么不用 slot.textContent：
 *   与 innerHTML 同理，slot.textContent 返回的是 fallback 内容，
 *   而非从 light DOM 分配过来的实际文本。
 *
 * @param slot - HTMLSlotElement 实例，为 undefined/null 时返回空字符串
 * @returns 分配内容的纯文本字符串
 */
export function getTextContent(slot: HTMLSlotElement | undefined | null): string {
  if (!slot) {
    return '';
  }
  const nodes = slot.assignedNodes({ flatten: true });
  let text = '';

  [...nodes].forEach(node => {
    if (node.nodeType === Node.TEXT_NODE) {
      text += node.textContent;
    }
  });

  return text;
}
