import { CSSResult, html } from 'lit';
import { XUIElement } from '../../flame.js';
import { util } from '../../internal/utils.js';
import styles from './taskbar.style.js';

export default class XTaskBar extends XUIElement {
  static styles: CSSResult = styles;
  static defaultOptions = { park: 'top' };

  willUpdate(): void {
    super.willUpdate();
    util.setPosition(this.shadowRoot?.host as HTMLElement, this.options.park);
  }

  render() {
    return html`
      <div>
        <slot name="task-menu"></slot>
      </div>
      <div>
        <slot name="task-logo"></slot>
      </div>
      <div>
        <slot name="task-item"></slot>
      </div>
      <div>
        <slot name="task-logon"></slot>
      </div>
    `;
  }
}
