import { css } from 'lit';
import componentStyles from '../../styles/component.styles';

export default css`
  ${componentStyles}

  :host {
    position: absolute;
    background: linear-gradient(90deg, #03a9f4, #03a9f4, #adfaea);
  }

  :host > div {
    position: relative;
    display: flex;
    float: left;
    height: 100%;
    flex-direction: row;
    align-items: center;
  }
`;
