import { CSSResult, html } from 'lit';
import { property, state } from 'lit/decorators.js';
import { classMap } from 'lit/directives/class-map.js';
import { unsafeHTML } from 'lit/directives/unsafe-html.js';
import MarkdownIt from 'markdown-it';
import styles from './chat.style.js';
import XUIElement from '../../internal/abstract.js';

interface ChatMessage {
  id: string;
  content: string;
  role: 'user' | 'assistant';
  timestamp: number;
}

interface FlameRPC {
  jsonrpc?: string;
  id?: string;
  method?: string;
  params?: Record<string, unknown>;
  result?: unknown;
  error?: string;
}

export default class XChat extends XUIElement {
  static styles: CSSResult = styles;

  static defaultOptions = {
    placeholder: '发送消息...',
    width: 400,
    height: 500,
  };

  @property({ type: String }) title = 'Title';

  @property({ type: String }) url = '';

  @state() private messages: ChatMessage[] = [];
  @state() private inputText = '';
  @state() private connected = false;
  @state() private connecting = false;
  @state() private streaming = false;

  private ws: WebSocket | null = null;
  private messageId = 0;
  private pendingMessages = new Map<string, ChatMessage>();
  private heartbeatInterval: number | null = null;
  private readonly HEARTBEAT_INTERVAL = 30000;

  initialize() {
    super.initialize();
    if (this.url) {
      /**
       * 问题原因：WebSocket 在组件初始化期间过早连接，导致竞态条件引发 EOFException
       * 修复方案：使用 requestAnimationFrame 延迟连接，确保组件完全渲染后再建立 WebSocket 连接
       */
      requestAnimationFrame(() => this.connectWebSocket());
    }
  }

  disconnectedCallback() {
    super.disconnectedCallback();
    this.stopHeartbeat();
    this.disconnectWebSocket();
  }

  private connectWebSocket() {
    if (this.ws && this.ws.readyState === WebSocket.OPEN) {
      return;
    }

    this.connecting = true;
    try {
      this.ws = new WebSocket(this.url);

      this.ws.onopen = () => {
        this.connected = true;
        this.connecting = false;
        console.log('Claw WebSocket connected');
        this.startHeartbeat();
      };

      this.ws.onmessage = (event) => {
        try {
          const rpc = JSON.parse(event.data) as FlameRPC;
          if (rpc.result === 'pong') {
            console.debug('Received pong from server');
            return;
          }
          this.handleMessage(event.data);
        } catch (e) {
          this.handleMessage(event.data);
        }
      };

      this.ws.onerror = (error) => {
        console.error('Claw WebSocket error:', error);
        this.connecting = false;
      };

      this.ws.onclose = () => {
        this.connected = false;
        this.connecting = false;
        this.stopHeartbeat();
        console.log('Claw WebSocket closed');
        setTimeout(() => this.connectWebSocket(), 3000);
      };
    } catch (e) {
      console.error('Failed to connect WebSocket:', e);
      this.connecting = false;
    }
  }

  private disconnectWebSocket() {
    if (this.ws) {
      this.stopHeartbeat();
      this.ws.close();
      this.ws = null;
    }
  }

  private startHeartbeat() {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
    }
    this.heartbeatInterval = window.setInterval(() => {
      if (this.ws && this.ws.readyState === WebSocket.OPEN) {
        const pingMessage = {
          jsonrpc: '2.0',
          id: `ping-${Date.now()}`,
          thing: 'WS:/WebSocket/Claw',
          method: 'ping'
        };
        this.ws.send(JSON.stringify(pingMessage));
        console.debug('Sent ping to server');
      }
    }, this.HEARTBEAT_INTERVAL);
  }

  private stopHeartbeat() {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
      this.heartbeatInterval = null;
    }
  }

  private handleMessage(data: string) {
    try {
      const rpc = JSON.parse(data) as FlameRPC;

      if (rpc.result !== undefined && rpc.id) {
        const pendingMsg = this.pendingMessages.get(rpc.id);
        if (pendingMsg) {
          const resultText = String(rpc.result);
          if (resultText === 'Message received, processing...') {
            pendingMsg.content = '🤔 正在思考...';
          } else {
            pendingMsg.content = resultText;
            this.streaming = false;
          }
          this.messages = [...this.messages];
        } else {
          const newMessage: ChatMessage = {
            id: rpc.id,
            content: String(rpc.result),
            role: 'assistant',
            timestamp: Date.now(),
          };
          this.messages = [...this.messages, newMessage];
          this.streaming = false;
        }
      } else if (rpc.error) {
        const pendingMsg = this.pendingMessages.get(rpc.id || '');
        if (pendingMsg) {
          pendingMsg.content = `Error: ${rpc.error}`;
          this.messages = [...this.messages];
          this.pendingMessages.delete(rpc.id || '');
          this.streaming = false;
        }
      }
    } catch (e) {
      console.error('Failed to parse message:', e);
    }
  }

  private sendMessage() {
    if (!this.inputText.trim() || !this.connected || this.streaming) {
      return;
    }

    const content = this.inputText.trim();
    this.inputText = '';

    const textarea = this.shadowRoot?.querySelector('.message-input') as HTMLTextAreaElement;
    if (textarea) {
      textarea.style.height = 'auto';
    }

    const userMessage: ChatMessage = {
      id: `msg-${++this.messageId}`,
      content,
      role: 'user',
      timestamp: Date.now(),
    };

    this.messages = [...this.messages, userMessage];

    const rpcId = `rpc-${++this.messageId}`;
    const assistantMessage: ChatMessage = {
      id: rpcId,
      content: '...',
      role: 'assistant',
      timestamp: Date.now(),
    };
    this.messages = [...this.messages, assistantMessage];
    this.pendingMessages.set(rpcId, assistantMessage);
    this.streaming = true;

    const rpc: FlameRPC = {
      jsonrpc: '2.0',
      id: rpcId,
      method: 'message',
      params: { content },
    };

    this.ws?.send(JSON.stringify(rpc));
    this.scrollToBottom();
  }

  private handleInput(e: Event) {
    const textarea = e.target as HTMLTextAreaElement;
    this.inputText = textarea.value;
    textarea.style.height = 'auto';
    textarea.style.height = Math.min(textarea.scrollHeight, 120) + 'px';
  }

  private handleKeyDown(e: KeyboardEvent) {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      this.sendMessage();
    }
  }

  private scrollToBottom() {
    setTimeout(() => {
      const container = this.shadowRoot?.querySelector('.messages');
      if (container) {
        container.scrollTop = container.scrollHeight;
      }
    }, 10);
  }

  private formatTime(timestamp: number): string {
    const date = new Date(timestamp);
    return date.toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' });
  }

  /** 将 Markdown 文本解析为 HTML。 */
  private parseMarkdown(content: string): string {
    if (!content) return '';
    const normalized = content.replace(/\\n/g, '\n');
    const md = new MarkdownIt({ html: true, breaks: true });
    return md.render(normalized).trim();
  }

  render() {
    return html`
      <div class="x-root">
        <header class="chat-header">
          <span class="title">${this.title}</span>
          <span class="status ${classMap({ connected: this.connected, connecting: this.connecting })}">
            ${this.connecting ? '连接中...' : this.connected ? '在线' : '离线'}
          </span>
        </header>
        <div class="messages">
          ${this.messages.length === 0
            ? html`<div class="empty-tip">开始与 Claw AI 对话吧</div>`
            : this.messages.map(
                (msg) => html`
                  <div class="message ${msg.role}">
                    <div class="message-avatar">
                      ${msg.role === 'user' ? '👤' : '🤖'}
                    </div>
                    <div class="message-body">
                      <div class="message-content">${unsafeHTML(this.parseMarkdown(msg.content))}</div>
                      <div class="message-time">${this.formatTime(msg.timestamp)}</div>
                    </div>
                  </div>
                `
              )}
        </div>
        <footer class="chat-footer">
          <textarea class="message-input"
            placeholder="${this.options.placeholder}"
            rows="1"
            .value="${this.inputText}"
            @input="${this.handleInput}"
            @keydown="${this.handleKeyDown}"
            ?disabled="${!this.connected}"
          ></textarea>
          <button class="send-btn" @click="${this.sendMessage}" ?disabled="${!this.connected || !this.inputText.trim()}">
            发送
          </button>
        </footer>
      </div>
    `;
  }
}
