import { css } from 'lit';
import componentStyles from '../../styles/component.styles';

export default css`
  ${componentStyles}
  :host {
    position: absolute;
  }
  .x-root {
    display: flex;
    position: absolute;
    flex-direction: column;
    inset: 0px;
  }
  .x-root.bordered {
    border: 1px solid #d0d0d0;
  }
  .x-root > header {
    display: flex;
    position: relative;
    flex-direction: row;
    background: #80cefc;
    width: 100%;
  }
  .x-root > main {
    flex: 1;
    position: relative;
  }
  .x-root > footer {
    position: relative;
    background: #80cefc;
    width: 100%;
  }
  .draggable:hover {
    cursor: move;
  }
  .h-left {
    flex: 1;
    display: inline-flex;
    align-items: center;
    justify-content: flex-start;
  }
  .h-left > i {
    font-size: 12px;
    font-style: normal;
    margin-left: 4px;
  }
  .h-right {
    display: inline-flex;
    align-items: center;
    justify-content: flex-end;
  }
  .h-right > i {
    cursor: pointer;
  }
  .h-right i:hover {
    cursor: pointer;
    border-radius: 4px;
    filter: invert(80%);
  }
  .mask {
    position: absolute;
    visibility: hidden;
    border: 1px dashed #939393;
    cursor: move;
  }
`;
