import { CSSResult, html, nothing } from 'lit';
import { property } from 'lit/decorators.js';
import { util } from '../../internal/utils.js';
import { classMap } from 'lit/directives/class-map.js';
import { styleMap } from 'lit/directives/style-map.js';
import XUIElement from '../../internal/abstract.js';
import { HasSlotController } from '../../internal/slot.js';
import styles from './panel.style.js';

export default class XPanel extends XUIElement {
  static styles: CSSResult = styles;
  static defaultOptions = { park: 'top', header: { height: 24 }, footer: { height: 0 }, draggable: false, border: false };

  @property({ type: String, reflect: true }) title = '';

  /** Slot 检测控制器，监听 default / icon / text / actions / footer 五个插槽的内容变化并支持同步检测 */
  protected slotController = new HasSlotController(this, '[default]', 'icon', 'text', 'actions', 'footer');

  public maximize(_e: MouseEvent) {}

  public dragPanel(_e: MouseEvent) {}

  public refresh() {
    if (util.isBlank(this.options.url)) {
      return;
    } else {
      const newUrl = util.marginUrl(this.options.url, this.options.params);
      this.load(this.toS(newUrl));
    }
  }

  public hide() {
    this.style.visibility = 'hidden';
    this.style.display = 'none';
  }

  public show() {
    this.style.visibility = 'visible';
    this.style.display = 'block';
  }

  public getMask() {
    return this.shadowRoot?.querySelector(':host>.mask') as HTMLElement;
  }

  public load(href: string, callback?: any, useFetch?: boolean) {
    if (util.isBlank(href)) return;
    /**
     * 问题：通过slot占位加载EasyUI的组件时,组件的高度参考的时x-window的尺寸,但是XWindow包含Header的部分,导
     * 致innerHTML加载进slot后导致超高的问题;
     * 办法：在x-window添加子元素<div style="position:absolute;left:0px;right:0px;top:0px;bottom:0px">,
     * 加载的内容加入进创建的子内容中;
     */
    this.innerHTML = '';
    const element = document.createElement('div');
    util.setStyle(element, { position: 'absolute', inset: '0px' });

    (this as HTMLElement).appendChild(element);
    if (useFetch) {
      util.xuiLoad(element, href, callback);
    } else {
      util.euiLoad(element, href, callback);
    }
  }

  iframe(href: string) {
    if (util.isBlank(href)) return;
    this.innerHTML = '';
    const element = document.createElement('iframe');
    util.setStyle(element, { position: 'absolute', border: 0, top: '0px', left: '0px', width: '100%', height: '100%' });
    (this as HTMLElement).appendChild(element);
    element.src = href;
  }

  willUpdate(): void {
    super.willUpdate();
    util.setPosition(this as HTMLElement, this.options.park);
  }

  protected firstUpdated(): void {
    if (!util.isBlank(this.options.url)) {
      // 仅在作为 x-tab-panel 的直接子元素（即作为 tab）时跳过自动加载，
      // 由 tab-panel 的 active() 控制延迟加载。嵌套在 tab 内容内部的 x-panel 仍需自动加载。
      const parent = (this as HTMLElement).parentElement;
      const isDirectTab = parent && parent.tagName.toLowerCase() === 'x-tab-panel';
      if (!isDirectTab) {
        this.refresh();
      }
    }
  }

  render() {
    const hasFooter = this.slotController.test('footer');

    return html`
      <div class="${classMap({ 'x-root': true, bordered: this.options.border })}">
        ${this.options.header
          ? html`<header class="${classMap({ draggable: this.options.draggable })}" style="${styleMap({ height: this.options.header ? this.options.header.height + 'px' : '0px' })}">
              ${this._uiHeader()}
            </header>`
          : nothing}
        <main part="main">${this._uiMain()}</main>
        ${hasFooter
          ? html`<footer style="${styleMap({ height: this.options.footer ? this.options.footer.height + 'px' : '0px' })}">${this._uiFooter()}</footer>`
          : nothing}
      </div>
      <div class="mask"></div>
    `;
  }

  protected _uiHeader() {
    const hasIcon = !util.isBlank(this.icon);
    const hasTitle = !util.isBlank(this.title);

    let headerLeft;
    if (hasIcon && hasTitle) {
      headerLeft = html`<img part="icon" src="${this.icon}" /> <i part="title">${this.title}</i>`;
    } else if (hasIcon) {
      headerLeft = html`<img part="icon" src="${this.icon}" />`;
    } else if (hasTitle) {
      headerLeft = html`<i part="title">${this.title}</i>`;
    } else {
      headerLeft = nothing;
    }

    return html`<span class="h-left" @mousedown="${this.dragPanel}" @dblclick="${this.maximize}">
        ${headerLeft}
        <slot name="icon"></slot>
        <slot name="text"></slot>
      </span>
      <span class="h-right">
        <slot name="actions"></slot>
        ${this._uiActions()}
      </span>`;
  }

  protected _uiActions(): unknown {
    return nothing;
  }

  protected _uiMain() {
    return html`<slot></slot>`;
  }

  protected _uiFooter() {
    return html`<slot name="footer"></slot>`;
  }
}
