import { css } from 'lit';
import panelStyles from '../panel/panel.style.js';

export default css`
  ${panelStyles}
  :host {
    min-width: 100px;
    min-height: 100px;
    height: 100%;
  }
  .x-root > header {
    display: flex;
    flex-direction: row;
    align-items: center;
    background: #008bc7;
  }
  .x-root > header > i {
    flex: 1;
  }
  .x-root > header > ::slotted(*) {
    justify-items: flex-end;
    margin-right: 10px;
  }
  .x-root > main {
    flex: 1;
    display: flex;
    direction: row;
    background-color: white;
    overflow-x: hidden;
  }
  .x-root > main > section {
    flex: 1;
    overflow: auto;
  }
  .x-root > footer {
    justify-items: flex-end;
    height: 22px;
    background-color: #adfaea;
  }
  .sidebar {
    display: flex;
    width: 22px;
    flex-direction: column;
    justify-items: flex-end;
    align-items: center;
    background: linear-gradient(180deg, #008bc7, #008bc7, #adfaea);
  }
  .sidebar > i {
    color: white;
  }
  .sidebar > i:hover {
    color: #fcc617;
    cursor: pointer;
  }
  .rotate-text {
    overflow: visible;
    white-space: nowrap;
    transform-origin: 0 100%;
    transform: rotate(90deg);
    -moz-transform: rotate(90deg);
    -webkit-transform: rotate(90deg);
  }
  .chevron:before {
    content: '\\f137';
  }
  .lock:before {
    content: '\\f13e';
  }
  .unlock:before {
    content: '\\f09c';
  }
`;
